-      assert (0 <= red && red <= 255);
-      assert (0 <= green && green <= 255);
-      assert (0 <= blue && blue <= 255);
-      assert (0 <= alpha && alpha <= 255);
+      // Validate at runtime rather than via assert (disabled by default in
