    Validate LensBlurFilter sides and radius (#492)

    The jhlabs implementation computes `polyAngle = π / sides`. With
    `sides == 0` this divides by zero; with `sides < 3` it produces a
    degenerate "polygon" the bokeh-shape math doesn't handle.
    `KaleidoscopeFilter` already validates `sides ≥ 3` in this package;
    `LensBlurFilter` didn't.

    Co-authored-by: Claude Opus 4.7 (1M context) <noreply@anthropic.com>
---
 .../sksamuel/scrimage/filter/LensBlurFilter.java   |  8 ++++++
 .../filter/LensBlurFilterValidationTest.kt         | 31 ++++++++++++++++++++++
 2 files changed, 39 insertions(+)

diff --git a/scrimage-filters/src/main/java/com/sksamuel/scrimage/filter/LensBlurFilter.java b/scrimage-filters/src/main/java/com/sksamuel/scrimage/filter/LensBlurFilter.java
index 7d8a29a6..2696e791 100644
--- a/scrimage-filters/src/main/java/com/sksamuel/scrimage/filter/LensBlurFilter.java
+++ b/scrimage-filters/src/main/java/com/sksamuel/scrimage/filter/LensBlurFilter.java
@@ -25,6 +25,14 @@ public class LensBlurFilter extends BufferedOpFilter {
     private final int sides;

     public  LensBlurFilter(float radius, float bloom, float bloomThreshold, int sides) {
+        if (radius < 0)
+            throw new IllegalArgumentException("radius must be >= 0, got " + radius);
+        // The jhlabs implementation computes `polyAngle = π / sides` and
+        // walks the polygon vertices; sides < 3 either divides by zero
+        // (sides == 0) or produces a degenerate "polygon" of 1–2 vertices
+        // that the bokeh-shape math doesn't handle.
+        if (sides < 3)
+            throw new IllegalArgumentException("sides must be >= 3, got " + sides);
         this.radius = radius;
         this.bloom = bloom;
         this.bloomThreshold = bloomThreshold;
diff --git a/scrimage-filters/src/test/kotlin/com/sksamuel/scrimage/filter/LensBlurFilterValidationTest.kt b/scrimage-filters/src/test/kotlin/com/sksamuel/scrimage/filter/LensBlurFilterValidationTest.kt
new file mode 100644
