+      b = lerp(sx, u, v);
+
+      return 1.5f * lerp(sy, a, b);
+   }
+
+   /**
+    * Compute 3-dimensional Perlin noise.
+    *
+    * @param x the x coordinate
+    * @param y the y coordinate
+    * @return noise value at (x,y,z)
+    */
+   public static float noise3(float x, float y, float z) {
+      int bx0, bx1, by0, by1, bz0, bz1, b00, b10, b01, b11;
+      float rx0;
+      float rx1;
+      float ry0;
+      float ry1;
+      float rz0;
+      float rz1;
+      float[] q;
+      float sy;
+      float sz;
+      float a;
+      float b;
+      float c;
+      float d;
+      float t;
+      float u;
+      float v;
+      int i, j;
+
+      if (start) {
+         start = false;
+         init();
+      }
+
+      t = x + N;
+      bx0 = ((int) t) & BM;
+      bx1 = (bx0 + 1) & BM;
+      rx0 = t - (int) t;
+      rx1 = rx0 - 1.0f;
+
+      t = y + N;
+      by0 = ((int) t) & BM;
+      by1 = (by0 + 1) & BM;
+      ry0 = t - (int) t;
+      ry1 = ry0 - 1.0f;
+
+      t = z + N;
+      bz0 = ((int) t) & BM;
+      bz1 = (bz0 + 1) & BM;
+      rz0 = t - (int) t;
+      rz1 = rz0 - 1.0f;
+
+      i = p[bx0];
+      j = p[bx1];
+
+      b00 = p[i + by0];
+      b10 = p[j + by0];
+      b01 = p[i + by1];
+      b11 = p[j + by1];
+
+      t = sCurve(rx0);
+      sy = sCurve(ry0);
+      sz = sCurve(rz0);
+
+      q = g3[b00 + bz0];
+      u = rx0 * q[0] + ry0 * q[1] + rz0 * q[2];
+      q = g3[b10 + bz0];
+      v = rx1 * q[0] + ry0 * q[1] + rz0 * q[2];
+      a = lerp(t, u, v);
+
+      q = g3[b01 + bz0];
+      u = rx0 * q[0] + ry1 * q[1] + rz0 * q[2];
+      q = g3[b11 + bz0];
+      v = rx1 * q[0] + ry1 * q[1] + rz0 * q[2];
+      b = lerp(t, u, v);
+
+      c = lerp(sy, a, b);
+
+      q = g3[b00 + bz1];
+      u = rx0 * q[0] + ry0 * q[1] + rz1 * q[2];
+      q = g3[b10 + bz1];
+      v = rx1 * q[0] + ry0 * q[1] + rz1 * q[2];
+      a = lerp(t, u, v);
+
+      q = g3[b01 + bz1];
+      u = rx0 * q[0] + ry1 * q[1] + rz1 * q[2];
+      q = g3[b11 + bz1];
+      v = rx1 * q[0] + ry1 * q[1] + rz1 * q[2];
+      b = lerp(t, u, v);
+
+      d = lerp(sy, a, b);
+
+      return 1.5f * lerp(sz, c, d);
+   }
+
+   public static float lerp(float t, float a, float b) {
+      return a + t * (b - a);
+   }
+
+   private static void normalize2(float[] v) {
+      float s = (float) Math.sqrt(v[0] * v[0] + v[1] * v[1]);
+      v[0] = v[0] / s;
+      v[1] = v[1] / s;
+   }
+
+   static void normalize3(float[] v) {
+      float s = (float) Math.sqrt(v[0] * v[0] + v[1] * v[1] + v[2] * v[2]);
+      v[0] = v[0] / s;
+      v[1] = v[1] / s;
+      v[2] = v[2] / s;
+   }
+
+   private static int random() {
+      return randomGenerator.nextInt() & 0x7fffffff;
+   }
+
+   private static void init() {
+      int i, j, k;
+
+      for (i = 0; i < B; i++) {
+         p[i] = i;
+
+         g1[i] = (float) ((random() % (B + B)) - B) / B;
+
+         for (j = 0; j < 2; j++)
+            g2[i][j] = (float) ((random() % (B + B)) - B) / B;
+         normalize2(g2[i]);
+
+         for (j = 0; j < 3; j++)
+            g3[i][j] = (float) ((random() % (B + B)) - B) / B;
+         normalize3(g3[i]);
+      }
+
+      for (i = B - 1; i >= 0; i--) {
+         k = p[i];
+         p[i] = p[j = random() % B];
+         p[j] = k;
+      }
+
+      for (i = 0; i < B + 2; i++) {
+         p[B + i] = p[i];
+         g1[B + i] = g1[i];
+         for (j = 0; j < 2; j++)
+            g2[B + i][j] = g2[i][j];
+         for (j = 0; j < 3; j++)
+            g3[B + i][j] = g3[i][j];
+      }
+   }

 }

