+   protected static Path getPathFromProperty(String name) {
+      try {
+         String binaryDir = System.getProperty("com.sksamuel.scrimage.webp.binary.dir");
+         if (binaryDir != null && !binaryDir.isEmpty()) {
+            Path path = Paths.get(binaryDir, name);
